    function scrollWorkflowTestStepIntoView(stepId) {
      if (!stepId) return;
      Vue.nextTick(() => {
        const container = workflowTestTimelineRef.value;
        if (!container) return;
        const target = Array.from(container.querySelectorAll('[data-step-id]'))
          .find((el) => el.dataset.stepId === stepId);
        if (!target) return;
        const targetTop = target.offsetTop;
        const targetBottom = targetTop + target.offsetHeight;
        const viewTop = container.scrollTop;
        const viewBottom = viewTop + container.clientHeight;
        if (targetTop < viewTop + 12) {
          container.scrollTo({ top: Math.max(0, targetTop - 12), behavior: 'smooth' });
        } else if (targetBottom > viewBottom - 12) {
          container.scrollTo({ top: targetBottom - container.clientHeight + 12, behavior: 'smooth' });
        }
      });
    }

    function getWorkflowTestSceneContext() {
      return {
        processing: form.processing,
        documents: form.scene?.documents || [],
        scene: form.scene,
        verify: form.verify,
        docTypes: (form.scene?.documents || []).map((d) => d.type).filter(Boolean),
        getDocSchema,
        getDocLabel: getDocDisplayLabel,
      };
    }

    function applyWorkflowTestCanvasHighlights(summary) {
      clearWorkflowTestHighlight();
      const highlights = summary?.canvasHighlights || [];
      if (!highlights.length) return;
      workflowTestHighlightNodeId.value = highlights[0].nodeId;
      if (workflowTestHighlightTimer) window.clearTimeout(workflowTestHighlightTimer);
      workflowTestHighlightTimer = window.setTimeout(() => {
        clearWorkflowTestHighlight();
      }, 4200);
    }

    function runWorkflowTest(options = {}) {
      const err = validateWorkflowTestCase(workflowTestDraft.testCase);
      if (err) {
        ElementPlus.ElMessage.warning(err);
        workflowTestDraft.samplePanelOpen = true;
        return;
      }
      if (workflowTestRunning.value) return;
      const sceneContext = getWorkflowTestSceneContext();
      const steps = buildWorkflowTestSteps(getActiveWf(), workflowTestDraft.testCase, sceneContext);
      workflowTestDraft.steps = steps.map((step) => ({
        ...step,
        status: 'pending',
        summary: '未実行',
        errorReason: '',
        needsHuman: false,
      }));
      workflowTestDraft.artifacts = buildWorkflowTestArtifacts(workflowTestDraft.testCase);
      workflowTestDraft.hasRun = true;
      workflowTestRunning.value = true;
      workflowTestDraft.runningStepId = '';
      workflowTestDraft.summary = null;
      let index = 0;

      const finishWorkflowTestRun = (stopAtStepId = '') => {
        workflowTestRunning.value = false;
        workflowTestDraft.runningStepId = '';
        workflowTestDraft.summary = buildWorkflowTestSummary(
          workflowTestDraft.steps,
          workflowTestDraft.testCase,
          getActiveWf(),
          sceneContext,
        );
        applyWorkflowTestCanvasHighlights(workflowTestDraft.summary);
        if (options.updateSceneStatus !== false) {
          const testOk = workflowTestDraft.summary?.overallStatus === 'success';
          form.workflowTestStatus = testOk ? 'success' : 'failed';
          updateSceneReadyState();
          savedSnapshot.value = JSON.stringify(form);
          saveStorage(currentSceneId.value, form);
        }
        const failedStep = workflowTestDraft.steps.find((step) => step.status === 'error');
        workflowTestDraft.selectedStepId = stopAtStepId
          || failedStep?.id
          || workflowTestDraft.steps[workflowTestDraft.steps.length - 1]?.id
          || workflowTestDraft.selectedStepId;
        if (failedStep?.id) scrollWorkflowTestStepIntoView(failedStep.id);
        workflowTestRunTimer = null;
        const testOk = workflowTestDraft.summary?.overallStatus === 'success';
        if (testOk) {
          ElementPlus.ElMessage.success('テスト成功。画布状態を公開可能に更新しました');
        } else {
          const structureNote = workflowTestDraft.summary?.structureNote || '';
          ElementPlus.ElMessage.warning(
            failedStep?.errorReason
              ? `テスト失敗で停止：${failedStep.errorReason}`
              : (structureNote || 'Workflow テストが失敗しました'),
          );
        }
      };

      const advance = () => {
        if (index >= steps.length) {
          finishWorkflowTestRun();
          return;
        }
        const target = steps[index];
        workflowTestDraft.runningStepId = target.id;
        workflowTestDraft.selectedStepId = target.id;
        scrollWorkflowTestStepIntoView(target.id);
        index += 1;
        window.setTimeout(() => {
          const finalized = steps[index - 1];
          const rowIndex = workflowTestDraft.steps.findIndex((step) => step.id === finalized.id);
          if (rowIndex >= 0) workflowTestDraft.steps[rowIndex] = { ...finalized };
          workflowTestDraft.runningStepId = '';
          // 失败即停：后续节点保持「未実行」，不再继续测试
          if (finalized.status === 'error') {
            finishWorkflowTestRun(finalized.id);
            return;
          }
          advance();
        }, 420);
      };

      advance();
    }

